  --size-ps: 80px;         /* Partnership */
  --size-score: 200px;      /* Total Run */
  --size-overs: 100px;      /* Overs */

  /* ===== TEXT COLORS ===== */
  --color-team: #ffffff;
  --color-lastwkt: #ffff00;
  --color-need: #ffff00;
  --color-crr: #ffff00;
  --color-rrr: #ffff00;
